import React from 'react';
import { Link } from 'react-router-dom';

const PORTRAIT = 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80&auto=format&fit=crop';

const lenses = [
  {
    roman: 'I',
    title: 'Western Medicine',
    desc: 'An MD from Emory and years of clinical training give Fayzan a rigorous, biology-grounded lens on how physiology shapes cognition, behavior, and decision-making under pressure.',
    gradient: 'linear-gradient(135deg, #1e3a8a 0%, #134e4a 100%)',
    glow: 'rgba(59,130,246,0.3)',
  },
  {
    roman: 'II',
    title: 'Executive Coaching',
    desc: 'Thousands of hours mapping behavioral patterns, navigating organizational dynamics, and unlocking leadership capacity in high-stakes environments. PCC certified through the ICF.',
    gradient: 'linear-gradient(135deg, #7c2d12 0%, #9d174d 100%)',
    glow: 'rgba(249,115,22,0.3)',
  },
  {
    roman: 'III',
    title: 'Technology & Business',
    desc: 'As a former Google product leader and biotech operator, Fayzan understands the pressures of high-growth environments firsthand — and brings that lived experience directly into the coaching relationship.',
    gradient: 'linear-gradient(135deg, #4c1d95 0%, #1e3a8a 100%)',
    glow: 'rgba(139,92,246,0.3)',
  },
];

const credentials = [
  { label: 'Education', value: 'MD, Emory University School of Medicine' },
  { label: 'Certification', value: 'PCC — International Coaching Federation' },
  { label: 'Experience', value: 'Product Leader at Google · Series C Biotech' },
  { label: 'Practice', value: '1,000+ coaching hours with high performers' },
];

export default function About() {
  return (
    <div>
      {/* ── HERO ── */}
      <section style={{
        minHeight: '100vh',
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        overflow: 'hidden',
        position: 'relative',
      }} className="about-hero-grid">
        {/* Left */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'flex-end',
          padding: '100px 60px 80px',
          position: 'relative',
          zIndex: 2,
        }}>
          <div style={{
            position: 'absolute', inset: 0,
            background: 'linear-gradient(135deg, rgba(7,3,26,1) 0%, rgba(28,15,60,0.95) 100%)',
            zIndex: 0,
          }} />
          <div style={{
            position: 'absolute', bottom: '20%', left: '30%',
            width: '300px', height: '300px',
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(139,92,246,0.2) 0%, transparent 70%)',
            zIndex: 0,
          }} />
          <div style={{ position: 'relative', zIndex: 1 }}>
            <span className="label">About</span>
            <h1 style={{
              fontSize: 'clamp(36px, 5vw, 64px)',
              fontWeight: 700,
              color: '#f8f6ff',
              marginBottom: '16px',
              lineHeight: '1.1',
            }}>Fayzan Rab</h1>
            <p style={{
              fontSize: '15px',
              color: 'rgba(248,246,255,0.55)',
              letterSpacing: '0.02em',
            }}>MD, Emory University · PCC Certified · Former Google</p>
          </div>
        </div>

        {/* Right — portrait */}
        <div style={{ position: 'relative', overflow: 'hidden' }}>
          <img
            src={PORTRAIT}
            alt="Fayzan Rab portrait"
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              objectPosition: 'top center',
            }}
          />
          <div style={{
            position: 'absolute', inset: 0,
            background: 'linear-gradient(to right, rgba(7,3,26,0.4) 0%, transparent 50%)',
          }} />
          <div style={{
            position: 'absolute', bottom: 0, inset: '60% 0 0 0',
            background: 'linear-gradient(to top, rgba(7,3,26,0.6) 0%, transparent 100%)',
          }} />
        </div>

        <style>{`
          @media (max-width: 768px) {
            .about-hero-grid {
              grid-template-columns: 1fr !important;
              min-height: auto !important;
            }
            .about-hero-grid > div:first-child {
              padding: 120px 24px 50px !important;
              min-height: 50vh;
            }
            .about-hero-grid > div:last-child {
              height: 50vh;
            }
          }
        `}</style>
      </section>

      {/* ── THE STORY ── */}
      <section className="section">
        <div className="container">
          <div style={{
            display: 'grid',
            gridTemplateColumns: '1.2fr 1fr',
            gap: '80px',
            alignItems: 'start',
          }} className="two-col">
            {/* Left: Story */}
            <div>
              <span className="label">The Story</span>
              <h2 style={{ fontSize: 'clamp(26px, 3vw, 38px)', marginBottom: '24px', color: '#f8f6ff' }}>
                I was doing everything right — and it wasn't enough.
              </h2>
              <p style={{ color: 'rgba(248,246,255,0.65)', lineHeight: '1.8', marginBottom: '16px', fontSize: '15px' }}>
                I worked in Silicon Valley as a product leader at Google and a Series C biotech startup. Successful by most measures. But unfulfilled and unclear on what the highest utilization of my gifts would actually look like.
              </p>
              <p style={{ color: 'rgba(248,246,255,0.65)', lineHeight: '1.8', marginBottom: '16px', fontSize: '15px' }}>
                I tried many things before stumbling into executive coaching — where I saw the potential to create something unique to my voice and craft. I went to medical school at Emory and accumulated thousands of hours coaching high performers.
              </p>
              <p style={{ color: 'rgba(248,246,255,0.65)', lineHeight: '1.8', marginBottom: '32px', fontSize: '15px' }}>
                The goal was never just to help people get unstuck. It was to synthesize the best of medicine and coaching — to fully unleash what each person is already capable of.
              </p>
            </div>

            {/* Right: Credentials card */}
            <div style={{
              background: 'linear-gradient(135deg, rgba(139,92,246,0.12) 0%, rgba(59,130,246,0.08) 100%)',
              border: '1px solid rgba(139,92,246,0.2)',
              borderRadius: '20px',
              padding: '36px',
              backdropFilter: 'blur(10px)',
            }}>
              {/* Monogram */}
              <div style={{
                width: '60px', height: '60px',
                borderRadius: '14px',
                background: 'linear-gradient(135deg, #8b5cf6, #3b82f6)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '22px',
                fontWeight: 700,
                fontFamily: "'Playfair Display', serif",
                color: '#fff',
                marginBottom: '28px',
              }}>FR</div>

              {credentials.map(({ label, value }) => (
                <div key={label} style={{
                  paddingBottom: '20px',
                  marginBottom: '20px',
                  borderBottom: '1px solid rgba(255,255,255,0.06)',
                }}>
                  <span style={{
                    display: 'block',
                    fontSize: '10px',
                    fontWeight: 700,
                    letterSpacing: '0.16em',
                    textTransform: 'uppercase',
                    background: 'linear-gradient(135deg, #f97316, #8b5cf6)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                    marginBottom: '6px',
                  }}>{label}</span>
                  <span style={{ fontSize: '14px', color: '#f8f6ff', lineHeight: '1.5' }}>{value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        <style>{`
          @media (max-width: 768px) {
            .two-col { grid-template-columns: 1fr !important; gap: 40px !important; }
          }
        `}</style>
      </section>

      {/* ── THREE LENSES ── */}
      <section style={{
        padding: '80px 24px 100px',
        position: 'relative',
        overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', inset: 0,
          background: 'linear-gradient(180deg, transparent 0%, rgba(28,15,60,0.3) 50%, transparent 100%)',
        }} />
        <div className="container" style={{ position: 'relative', zIndex: 1 }}>
          <span className="label" style={{ display: 'block', textAlign: 'center' }}>Three Lenses</span>
          <h2 style={{
            fontSize: 'clamp(26px, 3.5vw, 42px)',
            textAlign: 'center',
            color: '#f8f6ff',
            marginBottom: '48px',
          }}>What informs the work</h2>

          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: '20px',
          }} className="three-col">
            {lenses.map(({ roman, title, desc, gradient, glow }) => (
              <div key={title} style={{
                background: gradient,
                borderRadius: '20px',
                padding: '32px 28px',
                position: 'relative',
                overflow: 'hidden',
                border: '1px solid rgba(255,255,255,0.1)',
                transition: 'all 0.3s ease',
              }}
              onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-6px)'; e.currentTarget.style.boxShadow = `0 20px 60px ${glow}`; }}
              onMouseLeave={e => { e.currentTarget.style.transform = 'none'; e.currentTarget.style.boxShadow = 'none'; }}
              >
                <div style={{
                  position: 'absolute',
                  bottom: '-8px', right: '16px',
                  fontSize: '72px',
                  fontFamily: "'Playfair Display', serif",
                  fontWeight: 700,
                  color: 'rgba(255,255,255,0.07)',
                  lineHeight: 1,
                  userSelect: 'none',
                }}>{roman}</div>
                <h3 style={{
                  fontFamily: "'Inter', sans-serif",
                  fontSize: '16px',
                  fontWeight: 700,
                  color: '#fff',
                  marginBottom: '12px',
                }}>{title}</h3>
                <p style={{
                  fontSize: '14px',
                  lineHeight: '1.7',
                  color: 'rgba(255,255,255,0.65)',
                }}>{desc}</p>
              </div>
            ))}
          </div>
        </div>

        <style>{`
          @media (max-width: 900px) {
            .three-col { grid-template-columns: 1fr !important; }
          }
        `}</style>
      </section>

      {/* ── LOGO STRIP ── */}
      <div className="logo-strip">
        <div className="container">
          <div className="logo-strip-inner">
            {['MD, Emory University', 'PCC Certified (ICF)', 'Google', 'TEDx Speaker'].map(item => (
              <span key={item} className="logo-strip-item">{item}</span>
            ))}
          </div>
        </div>
      </div>

      {/* ── CTA ── */}
      <section style={{ padding: '80px 24px' }}>
        <div className="container" style={{ textAlign: 'center' }}>
          <h2 style={{ fontSize: 'clamp(22px, 3vw, 36px)', color: '#f8f6ff', marginBottom: '12px' }}>
            Ready to explore working together?
          </h2>
          <p style={{ color: 'rgba(248,246,255,0.55)', marginBottom: '28px', fontSize: '15px' }}>
            Reach out to schedule an introductory conversation.
          </p>
          <Link to="/contact" className="btn btn-primary">Get in touch</Link>
        </div>
      </section>
    </div>
  );
}
